let eeLogos: Record<string, JSX.Element> = {};

/** Register additional icon logos. */
export function registerIcons(icons: { Logos?: Record<string, JSX.Element> }) {
    if (icons.Logos) {
        eeLogos = icons.Logos;
        Object.assign(Icons.Logos, icons.Logos);
    }
}

export const Icons = {
  Logos: {
    ...ceLogos,
    ...eeLogos,
  },
}